1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell", () => {
9	    expect(nextGeneration([[true]])).toEqual([]);
10	  });
11	  it("should return empty grid when all cells die from underpopulation", () => {
12	    expect(nextGeneration([[true, false], [false, false]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has exactly 2 live neighbors", () => {
15	    // Middle cell of [true, true, true] has exactly 2 live neighbors (left and right)
16	    expect(nextGeneration([[true, true, true]])).toEqual([[true]]);
17	  });
18	  it("should keep a live cell alive when it has exactly 3 live neighbors", () => {
19	    // 2x2 grid of live cells: each cell has exactly 3 live neighbors
20	    expect(nextGeneration([[true, true], [true, true]])).toEqual([[true, true], [true, true]]);
21	  });
22	  it("should kill a live cell with more than 3 live neighbors", () => {
23	    // A live cell with 4 live neighbors (overpopulation) dies
24	    // Use a cross pattern: center has 4 live neighbors
25	    //   false true  false
26	    //   true  true  true
27	    //   false true  false
28	    // Center cell (1,1) has 4 live neighbors -> dies (overpopulation)
29	    // Edge cells (0,1),(1,0),(1,2),(2,1) each have 3 live neighbors within grid bounds -> survive
30	    // Corner cells (0,0),(0,2),(2,0),(2,2) each have 3 live neighbors -> come alive (reproduction)
31	    // Next gen:
32	    //   true  true  true
33	    //   true  false true
34	    //   true  true  true
35	    const result = nextGeneration([
36	      [false, true, false],
37	      [true, true, true],
38	      [false, true, false],
39	    ]);
40	    expect(result).toEqual([
41	      [true, true, true],
42	      [true, false, true],
43	      [true, true, true],
44	    ]);
45	  });
46	  it("should bring a dead cell to life when it has exactly 3 live neighbors", () => {
47	    // L-shaped pattern: dead cell at (1,1) has exactly 3 live neighbors
48	    // true  true
49	    // true  false
50	    // Dead cell (1,1) neighbors: (0,0)=true, (0,1)=true, (1,0)=true -> 3 live neighbors -> comes alive
51	    expect(nextGeneration([[true, true], [true, false]])).toEqual([[true, true], [true, true]]);
52	  });
53	  it.todo("should produce correct next generation for blinker pattern");
54	  it.todo("should produce correct next generation for block still life pattern");
55	});
