it("should produce correct next generation for blinker pattern", () => {
  // Vertical blinker in 3x3 grid:
  // false true false
  // false true false
  // false true false
  // Next generation is horizontal blinker, cropped to 1x3:
  // true true true
  expect(nextGeneration([
    [false, true, false],
    [false, true, false],
    [false, true, false],
  ])).toEqual([[true, true, true]]);
});

